        "Answer all questions based only on the concepts taught in this session.",
        "Read each question carefully before responding.",
        "Ensure your answers are clear and scientifically accurate."
      ]
    },
    "blueprint": {
      "learningOutcomeCoverage": [],
      "difficultyDistribution": {
        "easy": 40,
        "medium": 40,
        "hard": 20
      },
      "bloomsDistribution": {
        "recall": 35,
