        "analysis": 0,
        "evaluation": 0
      },
      "questionDistribution": {
        "mcq": 4,
        "shortAnswer": 2,
        "longAnswer": 1
      },
      "timeAllocation": [
        {
          "section": "MCQ",
          "minutes": 5
        },
        {
          "section": "Short Answer",
          "minutes": 6
        },
        {
          "section": "Long Answer",
          "minutes": 4
        }
      ]
    },
    "mcq": [
      {
        "id": "MCQ-1",
        "question": "Which of the following best defines a 'tissue' in biological terms?",
        "options": [
          "A. A group of similar cells performing a specific function.",
          "B. An organ made up of different types of tissues working together.",
          "C. The smallest unit of life capable of independent existence.",
          "D. A collection of organs that form a system."
        ],
        "answer": "A",
        "explanation": "A tissue is defined as an aggregation of similar cells and their intercellular substances that perform a specific function.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO-Intro"
        ],
        "topicCoverage": [
          "Definition of Tissue"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      },
      {
        "id": "MCQ-2",
        "question": "In the context of plant tissues, which type is primarily responsible for providing mechanical strength and flexibility?",
        "options": [
          "A. Parenchyma",
          "B. Collenchyma",
          "C. Xylem",
          "D. Phloem"
        ],
        "answer": "B",
        "explanation": "Collenchyma tissues provide mechanical support and flexibility to growing parts of the plant due to their thickened corners.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO-PlantTypes"
        ],
        "topicCoverage": [
          "Mechanical Tissues in Plants"
        ],
        "difficulty": "easy",
        "bloomsLevel": "understanding"
      },
      {
        "id": "MCQ-3",
        "question": "Which of the following is a characteristic feature of Sclerenchyma cells?",
        "options": [
          "A. They are living and have thin cell walls.",
          "B. They contain large intercellular spaces for gas exchange.",
          "C. Their cell walls are thickened with lignin, making them dead at maturity.",
          "D. They are responsible for the transport of food in plants."
        ],
        "answer": "C",
        "explanation": "Sclerenchyma cells have heavily thickened secondary walls containing lignin and are typically dead when they become functional, providing hardness to plant parts.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO-PlantTypes"
        ],
        "topicCoverage": [
          "Sclerenchyma Characteristics"
        ],
        "difficulty": "medium",
        "bloomsLevel": "understanding"
      },
      {
        "id": "MCQ-4",
        "question": "What is the primary function of Xylem tissue in plants?",
        "options": [
          "A. Transporting food from leaves to other parts.",
          "B. Providing photosynthetic capability.",
          "C. Conducting water and minerals from roots to aerial parts.",
          "D. Storing starch for future use."
        ],
        "answer": "C",
        "explanation": "Xylem is the complex tissue responsible for the conduction of water and dissolved minerals from the roots up through the stem to the leaves.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO-ComplexTissues"
        ],
        "topicCoverage": [
          "Xylem Function"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      }
    ],
    "shortAnswer": [
      {
        "id": "SA-1",
        "question": "Differentiate between Parenchyma and Collenchyma tissues based on their cell wall thickness.",
        "answer": "Parenchyma cells have thin, uniform primary cell walls made of cellulose. In contrast, Collenchyma cells have unevenly thickened corners (corners are thicker than the rest) due to deposits of pectin and hemicellulose.",
        "expectedLength": "2 clear points comparing wall thickness",
        "marks": 2,
        "rubric": [
          "1 mark for correctly stating Parenchyma has thin/uniform walls.",
          "1 mark for correctly describing Collenchyma as having thickened corners."
        ],
        "learningOutcomeIds": [
          "LO-PlantTypes"
        ],
        "topicCoverage": [
          "Simple Tissues in Plants"
        ],
        "difficulty": "medium",
        "bloomsLevel": "understanding"
      },
      {
        "id": "SA-2",
        "question": "Why are Sclerenchyma cells described as 'dead' at maturity, and what is the significance of this?",
        "answer": "Sclerenchyma cells lose their protoplasm (cell contents) upon maturation. This allows them to form a rigid framework that provides maximum mechanical strength without metabolic cost.",
        "expectedLength": "2 clear points explaining status and function",
        "marks": 2,
        "rubric": [
          "1 mark for stating they are dead/lose protoplasm at maturity.",
          "1 mark for linking this to providing hardness/mechanical strength."
        ],
        "learningOutcomeIds": [
          "LO-PlantTypes"
        ],
        "topicCoverage": [
          "Sclerenchyma Characteristics"
        ],
        "difficulty": "medium",
        "bloomsLevel": "understanding"
      }
    ],
    "longAnswer": [
      {
        "id": "LA-1",
        "question": "Classify the complex tissues found in plants. For each type, describe its primary function and list two key structural components.",
        "answer": "The two main types of complex plant tissues are Xylem and Phloem.\n\n1. Xylem:\n   - Function: Conducts water and minerals from roots to leaves; provides mechanical support.\n   - Components: Tracheids, Vessels (also include xylem parenchyma and fibers).\n\n2. Phloem:\n   - Function: Transports food (photosynthates) from leaves to other parts of the plant.\n   - Components: Sieve tubes, Companion cells (also include phloem parenchyma and fibers).",
        "expectedLength": "4-5 well-structured points with explanation",
        "marks": 5,
        "rubric": [
          "1 mark for correctly identifying Xylem as a complex tissue.",
          "1 mark for stating the function of Xylem (water/mineral transport).",
          "1 mark for listing two components of Xylem (e.g., Tracheids/Vessels).",
          "2 marks for covering Phloem: 1 mark for identification/function, 1 mark for components.",
          "Bonus credit for clear structure and accurate terminology."
        ],
        "learningOutcomeIds": [
          "LO-ComplexTissues"
        ],
        "topicCoverage": [
          "Complex Tissues in Plants",
          "Xylem Structure",
          "Phloem Structure"
        ],
        "difficulty": "hard",
        "bloomsLevel": "understanding"
      }
    ],
    "answerKey": {
      "mcq": [
        {
          "answer": "A. A group of similar cells performing a specific function.",
          "explanation": "Definition of tissue matches option A.",
          "marks": 1
        },
        {
          "answer": "B. Collenchyma",
          "explanation": "Collenchyma provides mechanical strength and flexibility via thickened corners.",
          "marks": 1
        },
        {
          "answer": "C. Their cell walls are thickened with lignin, making them dead at maturity.",
          "explanation": "Sclerenchyma is characterized by lignified walls and being dead at functional stage.",
          "marks": 1
        },
        {
          "answer": "C. Conducting water and minerals from roots to aerial parts.",
          "explanation": "This is the primary physiological role of Xylem.",
          "marks": 1
        }
      ],
      "shortAnswer": [
        {
          "answer": "Parenchyma has thin, uniform walls. Collenchyma has unevenly thickened corners (pectin/hemicellulose).",
          "rubric": [
            "Correct description of Parenchyma wall thickness.",
            "Correct description of Collenchyma corner thickening."
          ],
          "marks": 2
        },
        {
          "answer": "They lose protoplasm at maturity. This makes them rigid and provides mechanical strength without metabolic cost.",
          "rubric": [
            "Mentioning they are dead/lose contents.",
            "Linking to structural support/strength."
          ],
          "marks": 2
        }
      ],
      "longAnswer": [
        {
          "answer": "Complex tissues: Xylem and Phloem. \nXylem Function: Water/mineral transport. Components: Tracheids, Vessels.\nPhloem Function: Food transport. Components: Sieve tubes, Companion cells.",
          "rubric": [
            "Identification of Xylem (1 mark).",
            "Function and components of Xylem (2 marks total).",
            "Identification of Phloem (1 mark).",
            "Function and components of Phloem (1 mark)."
          ],
          "marks": 5
        }
      ],
      "generalMarkingGuidance": [
        "Award full marks for correct identification of tissues.",
        "Accept variations in wording as long as the scientific meaning is preserved (e.g., 'food' vs 'photosynthates').",
        "For structural components, listing any two valid parts from the specific tissue earns credit."
      ]
    }
  }
}
